122	static void
123	push_clip_stack(fz_context *ctx, fz_device *dev, fz_rect rect, int type)
124	{
125		if (dev->container_len == dev->container_cap)
126		{
127			int newmax = dev->container_cap * 2;
128			if (newmax == 0)
129				newmax = 4;
130			dev->container = fz_realloc_array(ctx, dev->container, newmax, fz_device_container_stack);
131			dev->container_cap = newmax;
132		}
133		if (dev->container_len == 0)
134			dev->container[0].scissor = rect;
135		else
136		{
137			dev->container[dev->container_len].scissor = fz_intersect_rect(dev->container[dev->container_len-1].scissor, rect);
138		}
139		dev->container[dev->container_len].type = type;
140		dev->container[dev->container_len].user = 0;
141		dev->container_len++;
142	}
143	
144	static void
145	pop_clip_stack(fz_context *ctx, fz_device *dev, int type)
146	{
147		if (dev->container_len == 0 || dev->container[dev->container_len-1].type != type)
148		{
149			fz_disable_device(ctx, dev);
150			fz_throw(ctx, FZ_ERROR_ARGUMENT, "device calls unbalanced");
151		}
152		dev->container_len--;
153	}
154	
155	static void
156	pop_push_clip_stack(fz_context *ctx, fz_device *dev, int pop_type, int push_type)
157	{
158		if (dev->container_len == 0 || dev->container[dev->container_len-1].type != pop_type)
159		{
160			fz_disable_device(ctx, dev);
161			fz_throw(ctx, FZ_ERROR_ARGUMENT, "device calls unbalanced");
162		}
163		dev->container[dev->container_len-1].type = push_type;
164	}
