535	fz_begin_tile_tid(fz_context *ctx, fz_device *dev, fz_rect area, fz_rect view, float xstep, float ystep, fz_matrix ctm, int id, int doc_id)
536	{
537		int result = 0;
538	
539		if (dev == NULL)
540			return 0;
541	
542		push_clip_stack(ctx, dev, area, fz_device_container_stack_is_tile);
543	
544		if (xstep < 0)
545			xstep = -xstep;
546		if (ystep < 0)
547			ystep = -ystep;
548		if (dev->begin_tile)
549		{
550			fz_try(ctx)
551				result = dev->begin_tile(ctx, dev, area, view, xstep, ystep, ctm, id, doc_id);
552			fz_catch(ctx)
553			{
554				fz_disable_device(ctx, dev);
555				fz_rethrow(ctx);
556			}
557		}
558	
559		return result;
560	}
