1160	fz_eval_function(fz_context *ctx, fz_function *func, const float *in, int inlen, float *out, int outlen)
1161	{
1162		float fakein[FZ_FUNCTION_MAX_M];
1163		float fakeout[FZ_FUNCTION_MAX_N];
1164		int i;
1165	
1166		if (inlen < func->m)
1167		{
1168			for (i = 0; i < inlen; ++i)
1169				fakein[i] = in[i];
1170			for (; i < func->m; ++i)
1171				fakein[i] = 0;
1172			in = fakein;
1173		}
1174	
1175		if (outlen < func->n)
1176		{
1177			func->eval(ctx, func, in, fakeout);
1178			for (i = 0; i < outlen; ++i)
1179				out[i] = fakeout[i];
